declare @storedID nvarchar(4000), @show nvarchar(4000), @allow_null nvarchar(4000), @form nvarchar(4000), @name nvarchar(4000), @idDefault int
declare @message nvarchar(4000), @unitName nvarchar(1023), @costUnit char(1)

select top 1 @idDefault = id from xdmgt order by stt
select @form = '', @name = ''

select @form = @form + rtrim(id) + char(255), @name = @name + case when lower(@@language) = 'v' then rtrim(stored_name) else rtrim(stored_name2) end + char(255) from xdmgt where status = '1' order by stt
select @form = left(@form, len(@form) - 1), @name = left(@name, len(@name) - 1)

if @@action = 'Edit' select @storedID = id from @@table where stt_rec = @stt_rec
select @show = show, @allow_null = allow_null from xdmgt where id = isnull(@storedID, @idDefault)

select @costUnit = rtrim(val) from options where name = 'm_gt_dvcs'
if isnull(@storedID, @idDefault) = 3 begin&ControlExtension; end
  else begin&ControlOptions; end
select @message = 'f = this; f._costUnit=' + case when @costUnit = '1' then 'true' else 'false' end + ';f._itemValue=''' + rtrim(@form) + ''';f._itemText=''' + dbo.FastBusiness$Function$EncodeScript(@name) + ''';initForm(this);'
select @message = @message + 'f._show = ''' + isnull(@show, '') + '''; f._allowNull = ''' + isnull(@allow_null, '') + '''; validCostCalculate(f, 1);'
if @costUnit = '1' begin
  select @unitName = case when @@language = 'v' then ten_dvcs else ten_dvcs2 end from dmdvcs where ma_dvcs = @@unit
  select @message = @message + 'f._unitCode=''' + @@unit + ''';f._unitName=''' + replace(replace(isnull(@unitName, ''), '\', '\\'), '''', '\''') + ''';'
end else begin
  select @message = @message + 'f._controlFocus = f.getItem(''&ControlFocus;'');setObjectFormHidden(f, ''ma_dvcs'', false);'
end

select @message as message
return






if @@view = 0 begin
  if @@action = 'Edit' begin
    if exists(select 1 from options where name = 'm_gt_dvcs' and val = '1') begin
      if @@admin <> 1 begin
        declare @ma_dvcs varchar(33)
        select @ma_dvcs = ma_dvcs from @@table where stt_rec = @stt_rec
        if not exists(select 1 from sysunitrights where user_id = @@userID and ma_dvcs = @ma_dvcs and r_edit = 1) begin
          select '' as script, '$NotAuthorized' as message
          return
        end
      end
    end
  end
end

