function active$AdvancedCalculation(f) {
  f.add_onResponseComplete(on$AdvancedCalculation$ResponseComplete);
  validCostCalculate(f, 1);
}

function closeFormDir(f) {try {f.remove_onResponseComplete(on$AdvancedCalculation$ResponseComplete);} catch (ex) {}}
function on$AdvancedCalculation$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'CostCalculate':
      f._show = result[0].Value;
      f._allowNull = result[1].Value;
      validCostCalculate(f, false);
      break;
    case 'Unit':
      f.getItem('buoc_tinh').value = result[0].Value;
      break;
    default:
      break;
  }
}
function onChange$AdvancedCalculation$CostCalculateForm(o) {o.parentForm.request('CostCalculate', 'CostCalculate', ['id']);}
function onChange$Unit(o) {
  var f = o.parentForm;
  if (f._action == 'New') f.request('Unit', 'Unit', ['ma_dvcs']);
  f.setReferenceKeyFilter('ma_bp');
  f.setReferenceKeyFilter('ma_yt');
  f.setReferenceKeyFilter('tk_cl');
}

function setItemDisable(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    if ($func.trim(a[i]) != '') {
      var o = f.getItem($func.trim(a[i]));
      if (o.a) $common.setVisible(o.a, !v);
      o.disabled = v;
    }
  }
}
function setValueDefault(f) {if (f._action == 'New') f.getItem('buoc_tinh').value = f._step;}
function setItemAllowNulls(f, c, v) {
  var a = c.split(','), o, grandNode;
  for (var i = 0; i < a.length; i++) {
    if ($func.trim(a[i]) != '') {
      o = f.getItem($func.trim(a[i]));
      o.field.AllowNulls = !v
      grandNode = o.parentNode.parentNode;
      if (v) {
        Sys.UI.DomElement.addCssClass(grandNode, 'Required');
        Sys.UI.DomElement.addCssClass(grandNode, f._id);
      }
      else Sys.UI.DomElement.removeCssClass(grandNode, 'Required');
    }
  }
}
function validCostCalculate(f, v) {
  var a = 'ma_gd, ma_bp, loai_yt, ma_yt, ma_kho, nhom_kho, loai_vt, nh_vt1, nh_vt2, nh_vt3, tao_pxcl, tk_cl';
  var t = getFiledFocus(a, f._show);
  window.setTimeout(String.format('setFocusWhenCostCalculateChange(\'{0}\', \'{1}\', {2});', f._id, t, v), 2);
  setItemDisable(f, a, true);
  setItemAllowNulls(f, a, false);
  if (f._show) {
    setItemDisable(f, f._show, false);
    if (f._allowNull) {setItemAllowNulls(f, f._allowNull, true);}
  }
  else {
    setItemDisable(f, a, true);
  }
  if (f._show.indexOf('ma_bp') != -1) f.setReferenceKeyFilter('ma_bp');
  if (f._show.indexOf('ma_yt') != -1) f.setReferenceKeyFilter('ma_yt');
  if (f._show.indexOf('tk_cl') != -1) f.setReferenceKeyFilter('tk_cl');
}
function getFiledFocus(c, s) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    if (s.indexOf($func.trim(a[i])) > -1)
    return $func.trim(a[i]);
  }
  return '';
}
function setFocusWhenCostCalculateChange(id, a, v) {
	var f = $find(id);
  var t1 = f.getItem('buoc_tinh'), t2, t3 = f.getItem('ma_gd');
  if (a == '') {t2 = f._findButton('Ok');}
  else {t2 = f.getItem(a);}
  if (!v) {
    if (t1.live){t1.focus();}
    else {if (t3.live) {t2.disabled = false; t2.focus();}}
  }
}
function setIndexCostCalculateForm(f, a) {
  var o = f.getItem('id');
  var index = 0;
  for (var i = 0; i < o.length; i++) {
    if (o[i].value == a) {
      index = i;
      break;
    }
  }
  o.options[index].selected = true;
}

function initForm(f) {
  var o = f.getItem('id'), value = f._itemValue.split(String.fromCharCode(255)), text = f._itemText.split(String.fromCharCode(255));
  for (var i = 0; i < value.length; i++) {o.options[i] = new Option(text[i], value[i]);}
}

